## 2. The OCaml implementation – `pcapng.ml`

```ocaml
(* ----------------------------------------------------------------------
   pcapng.ml  –  thin wrapper around the C stubs
   ---------------------------------------------------------------------- *)

type t = private Obj.t        (* abstract – only the C stub can create it *)
type frame = {
  timestamp : float;
  length    : int;
  data      : bytes;
}

exception Error of string

external caml_open_file : string -> t = "pcapng_open_file"
external caml_close      : t -> unit = "pcapng_close"
external caml_iter       : (frame -> unit) -> t -> unit = "pcapng_iter"
external caml_fold       : ('a -> frame -> 'a) -> 'a -> t -> 'a = "pcapng_fold"
external caml_next       : t -> frame option = "pcapng_next"
external caml_reset      : t -> unit = "pcapng_reset"

let open_file = caml_open_file
let close = caml_close
let iter = caml_iter
let fold = caml_fold
let next = caml_next
let reset = caml_reset
```

The only purpose of `pcapng.ml` is to expose the external functions with
the nice OCaml signatures defined in the `.mli`.  All the heavy lifting
happens in the C++ stub file.

---

## 3. The C++ stub – `pcapng_stubs.cpp`

> **Important:** this file **must be compiled as C++** (e.g. `g++ -c
> -I$(ocamlc -where) -I/path/to/libpcapng/include pcapng_stubs.cpp`).
> The resulting object file is then linked into the final shared library
> (`-lpcapng` or whatever the library name is).

```cpp
/* ----------------------------------------------------------------------
   pcapng_stubs.cpp  –  C++ implementation of the OCaml binding
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE          /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>
#include <caml/bigarray.h>

#include <pcapng.h>      // <-- whatever the libpcapng header is
#include <stdexcept>
#include <string>

/* ----------------------------------------------------------------------
   Helper: translate libpcapng exceptions into the OCaml exception
   ---------------------------------------------------------------------- */
static void raise_error(const std::string &msg)
{
    caml_raise_with_string(*caml_named_value("Pcapng.Error"), msg.c_str());
}

/* ----------------------------------------------------------------------
   OCaml representation of a frame (matching the record in pcapng.mli)
   ---------------------------------------------------------------------- */
static value caml_frame_of_pcapng(const pcapng::frame &f)
{
    CAMLparam0();
    CAMLlocal3(v_timestamp, v_length, v_data);

    /* 1. timestamp – a float */
    v_timestamp = caml_copy_double(f.timestamp());

    /* 2. length – an int */
    v_length = Val_int(f.captured_length());

    /* 3. data – a bytes block */
    size_t sz = f.data().size();
    v_data = caml_alloc_string(sz);
    memcpy(String_val(v_data), f.data().data(), sz);

    /* Build the record: 3 fields, tag 0 (records have tag 0) */
    value v = caml_alloc(3, 0);
    Store_field(v, 0, v_timestamp);
    Store_field(v, 1, v_length);
    Store_field(v, 2, v_data);

    CAMLreturn(v);
}

/* ----------------------------------------------------------------------
   The opaque OCaml value that holds the C++ reader object.
   ---------------------------------------------------------------------- */
struct caml_pcapng_reader {
    pcapng::Reader *reader;   // the actual libpcapng object
};

static void caml_pcapng_finalize(value v)
{
    caml_pcapng_reader *r = (caml_pcapng_reader *)Data_custom_val(v);
    delete r->reader;
    r->reader = nullptr;
}

/* The custom operations table – the only operation we need is finalisation */
static struct custom_operations caml_pcapng_ops = {
    "pcapng.reader",
    caml_pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* ----------------------------------------------------------------------
   Helper: allocate a fresh OCaml custom block wrapping a new Reader.
   ---------------------------------------------------------------------- */
static value caml_wrap_reader(pcapng::Reader *r)
{
    CAMLparam0();
    CAMLlocal1(v);

    v = caml_alloc_custom(&caml_pcapng_ops, sizeof(caml_pcapng_reader), 0, 1);
    caml_pcapng_reader *cr = (caml_pcapng_reader *)Data_custom_val(v);
    cr->reader = r;

    CAMLreturn(v);
}

/* ----------------------------------------------------------------------
   open_file : string -> t
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_open_file(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(v_res);

    const char *path = String_val(v_path);
    try {
        pcapng::Reader *r = new pcapng::Reader(path);
        v_res = caml_wrap_reader(r);
    } catch (const std::exception &e) {
        raise_error(e.what());
    }

    CAMLreturn(v_res);
}

/* ----------------------------------------------------------------------
   close : t -> unit
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_close(value v_handle)
{
    CAMLparam1(v_handle);
    caml_pcapng_reader *cr = (caml_pcapng_reader *)Data_custom_val(v_handle);
    if (cr->reader) {
        delete cr->reader;
        cr->reader = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   iter : (frame -> unit) -> t -> unit
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_iter(value v_fun, value v_handle)
{
    CAMLparam2(v_fun, v_handle);
    caml_pcapng_reader *cr = (caml_pcapng_reader *)Data_custom_val(v_handle);
    if (!cr->reader) caml_failwith("Pcapng.iter: handle already closed");

    pcapng::Reader &reader = *(cr->reader);

    /* Make the closure a GC root for the whole loop */
    caml_register_global_root(&v_fun);

    try {
        while (reader.has_next()) {
            pcapng::frame f = reader.next();   // copy the frame
            value v_frame = caml_frame_of_pcapng(f);

            /* Call the OCaml function.  If it raises, caml_callback
               returns the exception value; we re‑raise it. */
            value v_ret = caml_callback(v_fun, v_frame);
            if (Is_exception_result(v_ret))
                caml_raise(v_ret);
        }
    } catch (const std::exception &e) {
        caml_remove_global_root(&v_fun);
        raise_error(e.what());
    }

    caml_remove_global_root(&v_fun);
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   fold : ('a -> frame -> 'a) -> 'a -> t -> 'a
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_fold(value v_fun, value v_acc, value v_handle)
{
    CAMLparam3(v_fun, v_acc, v_handle);
    CAMLlocal1(v_new_acc);
    caml_pcapng_reader *cr = (caml_pcapng_reader *)Data_custom_val(v_handle);
    if (!cr->reader) caml_failwith("Pcapng.fold: handle already closed");

    pcapng::Reader &reader = *(cr->reader);

    caml_register_global_root(&v_fun);
    caml_register_global_root(&v_acc);   // keep the accumulator alive

    try {
        while (reader.has_next()) {
            pcapng::frame f = reader.next();
            value v_frame = caml_frame_of_pcapng(f);

            v_new_acc = caml_callback2(v_fun, v_acc, v_frame);
            if (Is_exception_result(v_new_acc))
                caml_raise(v_new_acc);

            /* replace the accumulator for the next iteration */
            v_acc = v_new_acc;
        }
    } catch (const std::exception &e) {
        caml_remove_global_root(&v_fun);
        caml_remove_global_root(&v_acc);
        raise_error(e.what());
    }

    caml_remove_global_root(&v_fun);
    caml_remove_global_root(&v_acc);
    CAMLreturn(v_acc);
}

/* ----------------------------------------------------------------------
   next : t -> frame option
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_next(value v_handle)
{
    CAMLparam1(v_handle);
    CAMLlocal1(v_res);
    caml_pcapng_reader *cr = (caml_pcapng_reader *)Data_custom_val(v_handle);
    if (!cr->reader) caml_failwith("Pcapng.next: handle already closed");

    try {
        if (!cr->reader->has_next())
            CAMLreturn(Val_int(0));            // None
        pcapng::frame f = cr->reader->next();
        value v_frame = caml_frame_of_pcapng(f);
        v_res = caml_alloc(1, 0);              // Some
        Store_field(v_res, 0, v_frame);
        CAMLreturn(v_res);
    } catch (const std::exception &e) {
        raise_error(e.what());
    }
}

/* ----------------------------------------------------------------------
   reset : t -> unit
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_reset(value v_handle)
{
    CAMLparam1(v_handle);
    caml_pcapng_reader *cr = (caml_pcapng_reader *)Data_custom_val(v_handle);
    if (!cr->reader) caml_failwith("Pcapng.reset: handle already closed");
    try {
        cr->reader->reset();
    } catch (const std::exception &e) {
        raise_error(e.what());
    }
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Register the OCaml exception name for use in raise_error.
   This code is executed once when the library is loaded.
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_init(value v_unit)
{
    CAMLparam1(v_unit);
    caml_register_named_value("Pcapng.Error", caml_named_value("Pcapng.Error"));
    CAMLreturn(Val_unit);
}
```

### How the stub works

| OCaml side | C++ stub side |
|------------|----------------|
| `type t` is an abstract value that actually **stores a custom block** (`caml_pcapng_reader`). | The custom block holds a pointer to `pcapng::Reader`. |
| `open_file` → `pcapng_open_file` | `new pcapng::Reader(path)`; the pointer is wrapped in a custom block. |
| `close` → `pcapng_close` | `delete reader;` (also done automatically by the finaliser). |
| `iter f h` → `pcapng_iter` | The stub loops over the C++ iterator, builds an OCaml `frame` record (`caml_frame_of_pcapng`), and calls `caml_callback` with the user supplied closure `f`.  If `f` raises, the exception bubbles out of the stub and is seen by the caller. |
| `fold g acc h` → `pcapng_fold` | Same idea, but the stub calls `caml_callback2` with the accumulator and the frame, returning the new accumulator. |
| `next` → `pcapng_next` | Returns `Some frame` or `None` using the OCaml option representation. |
| `reset` → `pcapng_reset` | Calls the C++ `reset` method. |

### Memory‑safety notes

* **Roots** – the closure (`v_fun`) and the accumulator (`v_acc`) are registered as global roots for the whole duration of the loop.  This guarantees that the OCaml GC cannot move or free them while we are still using them from C.  They are removed once the loop ends (or an exception is raised).
* **Exception handling** – any C++ exception is caught and turned into the OCaml exception `Pcapng.Error`.  If the user‑provided closure raises, we re‑raise the exact exception value (`caml_raise(v_ret)`) so that the caller sees it.
* **Finaliser** – if the OCaml value is GC‑collected without an explicit `close`, the finaliser `caml_pcapng_finalize` will delete the underlying C++ object, preventing leaks.

