## 4. Build instructions

```bash
# 1. Compile the C++ stub (adjust include paths as needed)
g++ -c -Wall -O2 -fPIC \
    -I$(ocamlc -where) \
    -I/path/to/libpcapng/include \
    pcapng_stubs.cpp

# 2. Build the OCaml library
ocamlopt -c pcapng.ml
ocamlopt -a -o libpcapng.cmxa pcapng.cmx pcapng_stubs.o -cclib -lpcapng

# 3. (Optional) Build a test program
cat > test.ml <<'EOF'
let () =
  let p = Pcapng.open_file Sys.argv.(1) in
  let i = ref 0 in
  Pcapng.iter (fun f ->
      Printf.printf "frame %d: %d bytes, ts=%f\n"
        !i f.length f.timestamp;
      incr i)
    p;
  Pcapng.close p
EOF

ocamlopt -o test.exe -I . libpcapng.cmxa test.ml
./test.exe sample.pcapng
```

You now have a **fully functional OCaml binding** that lets OCaml code run a user‑supplied callback for each frame in a pcapng file, while keeping the C++ iterator hidden behind a safe, GC‑aware interface.  

Feel free to extend the binding (e.g. expose more fields, add a streaming API, etc.) – the pattern shown here scales nicely because the heavy lifting stays in the C++ stub, and the OCaml side stays simple and type‑safe.
